mapper.select:
/* userApprMapper.getIdCheck */
SELECT APP_YN
FROM   CMN_USR_MST
WHERE  USR_ID = #{usrId}

/* userApprMapper.getHeadAgencyOrgnList */ SELECT OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) AS TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) AS ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) AS BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) AS ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) AS TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD) AS HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD != '30' AND ORGN_STAT_CD = '4' /* 가동 중인 대리점만 조회 */
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD >= 20

/* userApprMapper.getIdCheck */
SELECT MBLPHN_NUM
FROM   CMN_USR_MST
WHERE  USR_ID = #{appUsrId}
